  /* ---------- capacity ---------- */
  let capacityFilters={query:"",status:""};
  function memberCapacity(m){const tasks=rows(data().tasks).filter(t=>same(t.assigned_to,m.id)&&!done(t)&&!awaiting(t)),ops=window.INBESTIGA_V1711,estimated=tasks.reduce((n,t)=>n+Number(ops?.operation?.(t.id)?.estimated_minutes||t.estimated_minutes||60),0),actual=tasks.reduce((n,t)=>n+rows(ops?.efforts?.(t.id)).reduce((a,x)=>a+Number(x.validated_minutes??x.actual_minutes??0),0),0),capacity=Number(m.weekly_capacity_minutes||m.capacity_minutes||2400),ratio=capacity?estimated/capacity:0;let stateName="Disponible",className="available";if(ratio>=1.05){stateName="Sobrecargado";className="over"}else if(ratio>=.85){stateName="Cerca del límite";className="near"}else if(ratio>=.45){stateName="Carga adecuada";className="ok"}return {tasks,estimated,actual,capacity,ratio,stateName,className,late:tasks.filter(overdue).length,review:rows(data().tasks).filter(t=>same(t.assigned_to,m.id)&&awaiting(t)).length}}
  function renderWorkload1212(){if(!sectionVisible("workload")){q("#workload")?.setAttribute("data-v1212-pending","1");return}const root=q("#workload");if(!root)return;let members=rows(data().members).filter(m=>m.status!=="inactive").map(m=>({member:m,...memberCapacity(m)}));const needle=capacityFilters.query.toLowerCase();if(needle)members=members.filter(x=>`${x.member.full_name} ${x.member.position} ${x.member.role_code}`.toLowerCase().includes(needle));if(capacityFilters.status)members=members.filter(x=>x.className===capacityFilters.status);const summary={available:members.filter(x=>x.className==="available").length,ok:members.filter(x=>x.className==="ok").length,near:members.filter(x=>x.className==="near").length,over:members.filter(x=>x.className==="over").length};root.innerHTML=`<div class="module-title"><div><h2>Capacidad del equipo</h2><span class="small">Distribución de trabajo sin vigilancia invasiva.</span></div><span class="status blue">Cálculo agregado local</span></div><div class="v1212-capacity-summary">${[["Disponibles",summary.available],["Carga adecuada",summary.ok],["Cerca del límite",summary.near],["Sobrecargados",summary.over]].map(([a,b])=>`<div><span>${a}</span><strong>${b}</strong></div>`).join("")}</div><div class="v1212-capacity-toolbar"><input id="v1212CapacityQuery" placeholder="Buscar miembro" value="${html(capacityFilters.query)}"><select id="v1212CapacityStatus"><option value="">Todos los estados</option><option value="available">Disponible</option><option value="ok">Carga adecuada</option><option value="near">Cerca del límite</option><option value="over">Sobrecargado</option></select></div><div class="v1212-capacity-grid">${members.length?members.map(x=>`<article class="v1212-capacity-card"><div class="v1212-capacity-head"><div class="v1212-capacity-avatar">${x.member.avatar_data_url?`<img src="${html(x.member.avatar_data_url)}" loading="lazy">`:html((x.member.full_name||"IB").split(/\s+/).slice(0,2).map(v=>v[0]).join(""))}</div><div><strong>${html(x.member.full_name)}</strong><span>${html(x.member.position||x.member.role_code||"")}</span></div><b class="v1212-capacity-state ${x.className}">${x.stateName}</b></div><div class="v1212-capacity-bar"><i style="width:${Math.min(100,Math.round(x.ratio*100))}%"></i></div><div class="v1212-capacity-facts"><div><span>ASIGNADAS</span><strong>${x.tasks.length}</strong></div><div><span>ESTIMADO</span><strong>${html(mins(x.estimated))}</strong></div><div><span>REAL</span><strong>${html(mins(x.actual))}</strong></div><div><span>VENCIDAS</span><strong>${x.late}</strong></div><div><span>REVISIÓN</span><strong>${x.review}</strong></div><div><span>CAPACIDAD</span><strong>${Math.round(x.ratio*100)}%</strong></div></div></article>`).join(""):`<div class="v1212-empty">Sin miembros con estos filtros.</div>`}</div>`;q("#v1212CapacityStatus").value=capacityFilters.status;const update=debounce(()=>{capacityFilters={query:q("#v1212CapacityQuery")?.value||"",status:q("#v1212CapacityStatus")?.value||""};renderWorkload1212()},330);q("#v1212CapacityQuery").oninput=update;q("#v1212CapacityStatus").onchange=update}

