  window.INBESTIGA_V171212={version:VERSION,renderMyDay:renderMyDay1212,renderApprovals:renderApprovals1212,renderNotifications:renderNotifications1212,renderCalendar:renderCalendar1212,renderCapacity:renderWorkload1212,renderLibrary:renderAssets1212,renderRecovery:renderRecovery1212,resilience:{run:guarded,state:()=>({...resilience})},health:()=>({status:"ok",value:"Centro operativo v17.12.12",detail:"Módulos locales bajo demanda, sin polling ni canales Realtime adicionales."})};
